using System.IO;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.StaticFiles;

namespace MyApp.Controllers;

[ApiController]
[Route("files")]
public class FilesController : ControllerBase
{
    private readonly IWebHostEnvironment _environment;
    private readonly FileExtensionContentTypeProvider _contentTypeProvider;

    public FilesController(IWebHostEnvironment environment)
    {
        _environment = environment;
        _contentTypeProvider = new FileExtensionContentTypeProvider();
    }

    [HttpGet("{filename}")]
    public IActionResult GetFile(string filename)
    {
        if (string.IsNullOrWhiteSpace(filename))
            return BadRequest();

        var uploadsPath = Path.Combine(_environment.ContentRootPath, "uploads");
        var filePath = Path.Combine(uploadsPath, filename);

        var fullUploadsPath = Path.GetFullPath(uploadsPath);
        var fullFilePath = Path.GetFullPath(filePath);

        if (!fullFilePath.StartsWith(fullUploadsPath, System.StringComparison.OrdinalIgnoreCase))
            return BadRequest();

        if (!System.IO.File.Exists(fullFilePath))
            return NotFound();

        if (!_contentTypeProvider.TryGetContentType(fullFilePath, out var contentType))
            contentType = "application/octet-stream";

        var stream = new FileStream(fullFilePath, FileMode.Open, FileAccess.Read, FileShare.Read);
        return File(stream, contentType, enableRangeProcessing: true);
    }
}